    humanReasoning: { en: "A local model is a budget, not a magic file. Architecture and parameter count define the computation; GGUF packages weights and metadata for common runtimes; quantization stores approximate weights to trade memory and speed for some quality.", pt: "Um modelo local é um orçamento, não um arquivo mágico. Arquitetura e quantidade de parâmetros definem o cálculo; GGUF empacota pesos e metadados para runtimes comuns; quantização aproxima pesos para trocar memória e velocidade por alguma qualidade." },
    decomposition: { en: "Define the task and privacy requirement, inspect hardware, verify model license and provenance, estimate weight plus context memory, choose quantization, benchmark representative prompts, and record quality, latency, throughput, and failures.", pt: "Defina tarefa e privacidade, inspecione hardware, verifique licença e procedência, estime memória de pesos e contexto, escolha quantização, faça benchmark com prompts representativos e registre qualidade, latência, throughput e falhas." },
    flow: { en: "task and constraints → candidate model/license → hardware budget → format and quantization → runtime configuration → representative benchmark → measured decision", pt: "tarefa e restrições → modelo/licença → orçamento de hardware → formato e quantização → configuração do runtime → benchmark representativo → decisão medida" },
