    humanReasoning: { en: "Retrieval-augmented generation separates finding evidence from writing an answer. Documents are chunked and indexed; the query retrieves candidates; relevant context is placed in the prompt; the answer must remain bounded by that evidence.", pt: "RAG separa recuperação de evidência da redação da resposta. Documentos são divididos e indexados; a consulta recupera candidatos; contexto relevante entra no prompt; a resposta precisa permanecer limitada à evidência." },
    decomposition: { en: "Define document permissions, parse and version sources, choose chunk boundaries and metadata, compute local embeddings, index them, retrieve and optionally rerank, build a context budget, require citations, and evaluate retrieval separately from generation.", pt: "Defina permissões dos documentos, analise e versione fontes, escolha chunks e metadados, calcule embeddings locais, indexe, recupere e opcionalmente reordene, monte orçamento de contexto, exija citações e avalie recuperação separada da geração." },
    flow: { en: "authorized documents → parse/version → chunks + metadata → local embeddings → index → query embedding → retrieval/reranking → bounded context → grounded answer with citations → evaluation", pt: "documentos autorizados → parsing/versionamento → chunks + metadados → embeddings locais → índice → embedding da pergunta → recuperação/reranking → contexto limitado → resposta fundamentada com citações → avaliação" },
    pseudocode: { en: "INGEST authorized documents\nPARSE and version text\nCHUNK with source metadata\nEMBED locally\nINDEX vectors\nFOR each question\n  RETRIEVE candidates\n  RERANK if justified\n  BUILD context within token budget\n  INSTRUCT answer from context or say insufficient evidence\n  RETURN citations\nEVALUATE retrieval and answer separately", pt: "INGERIR documentos autorizados\nEXTRAIR e versionar texto\nDIVIDIR com metadados da fonte\nGERAR embeddings localmente\nINDEXAR vetores\nPARA cada pergunta\n  RECUPERAR candidatos\n  REORDENAR se justificado\n  MONTAR contexto dentro do orçamento\n  INSTRUIR resposta pela evidência ou declarar insuficiência\n  RETORNAR citações\nAVALIAR recuperação e resposta separadamente" },
    expertLens: { en: "A fluent answer cannot repair failed retrieval. Measure whether the right evidence was found, whether citations support each claim, and whether the system abstains when evidence is missing.", pt: "Resposta fluente não corrige recuperação ruim. Meça se a evidência correta foi encontrada, se citações sustentam cada afirmação e se o sistema se abstém quando falta evidência." },
    likelyFailure: { en: "Chunks without source metadata, embeddings from incompatible models, retrieving by similarity alone, prompt injection inside documents, stale indexes, citations that do not support claims, or evaluating only how convincing the prose sounds.", pt: "Chunks sem metadados, embeddings incompatíveis, recuperar apenas por similaridade, prompt injection em documentos, índice desatualizado, citações que não sustentam afirmações ou avaliar apenas a fluência." },
    transferPrompt: { en: "Design an evaluation set for a local document assistant with answerable, ambiguous, unanswerable, conflicting, stale, and prompt-injection cases.", pt: "Projete um conjunto de avaliação para assistente de documentos com casos respondíveis, ambíguos, sem resposta, conflitantes, desatualizados e com prompt injection." },
